const OAUTH_CONFIG = {
  authorizationEndpoint: 'https://your-auth-server.com/oauth/authorize',
  clientId: 'your-client-id',
  redirectUri: window.location.origin + '/callback',
  scope: 'read write',
  responseType: 'token'
};

const ALLOWED_ORIGINS = ['https://your-auth-server.com'];

const secureStorage = {
  setItem: (key, value, expiresIn) => {
    const item = {
      value: value,
      expiry: Date.now() + (expiresIn * 1000)
    };
    sessionStorage.setItem(key, JSON.stringify(item));
  },
  
  getItem: (key) => {
    const itemStr = sessionStorage.getItem(key);
    if (!itemStr) return null;
    
    try {
      const item = JSON.parse(itemStr);
      if (Date.now() > item.expiry) {
        sessionStorage.removeItem(key);
        return null;
      }
      return item.value;
    } catch (e) {
      return null;
    }
  },
  
  removeItem: (key) => {
    sessionStorage.removeItem(key);
  }
};

const generateSecureRandom = (length = 32) => {
  const array = new Uint8Array(length);
  crypto.getRandomValues(array);
  return Array.from(array, byte => byte.toString(16).padStart(2, '0')).join('');
};

const generateCodeVerifier = () => {
  return generateSecureRandom(32);
};

const sha256 = async (plain) => {
  const encoder = new TextEncoder();
  const data = encoder.encode(plain);
  const hash = await crypto.subtle.digest('SHA-256', data);
  return hash;
};

const base64urlencode = (buffer) => {
  const bytes = new Uint8Array(buffer);
  let str = '';
  bytes.forEach(byte => str += String.fromCharCode(byte));
  return btoa(str)
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/, '');
};

const generateCodeChallenge = async (verifier) => {
  const hashed = await sha256(verifier);
  return base64urlencode(hashed);
};

const sanitizeString = (str) => {
  if (typeof str !== 'string') return '';
  return str.replace(/[^\w\-\.~]/g, '');
};

const validateToken = (token) => {
  if (!token || typeof token !== 'string') return false;
  if (token.length < 10 || token.length > 2048) return false;
  if (!/^[A-Za-z0-9\-_\.~\+\/=]+$/.test(token)) return false;
  return true;
};

const validateState = (state) => {
  if (!state || typeof state !== 'string') return false;
  if (state.length !== 64) return false;
  if (!/^[a-f0-9]+$/.test(state)) return false;
  return true;
};

const parseFragment = (fragment) => {
  const params = new URLSearchParams(fragment.substring(1));
  const result = {};
  
  const allowedParams = ['access_token', 'token_type', 'expires_in', 'state', 'error', 'error_description'];
  
  for (const [key, value] of params.entries()) {
    if (allowedParams.includes(key)) {
      result[key] = value;
    }
  }
  
  return result;
};

const initiateOAuthFlow = async () => {
  const state = generateSecureRandom(32);
  const nonce = generateSecureRandom(32);
  
  secureStorage.setItem('oauth_state', state, 600);
  secureStorage.setItem('oauth_nonce', nonce, 600);
  secureStorage.setItem('oauth_timestamp', Date.now().toString(), 600);
  
  const params = new URLSearchParams({
    response_type: OAUTH_CONFIG.responseType,
    client_id: OAUTH_CONFIG.clientId,
    redirect_uri: OAUTH_CONFIG.redirectUri,
    scope: OAUTH_CONFIG.scope,
    state: state,
    nonce: nonce
  });
  
  const authUrl = `${OAUTH_CONFIG.authorizationEndpoint}?${params.toString()}`;
  
  window.location.href = authUrl;
};

const handleCallback = () => {
  const fragment = window.location.hash;
  
  if (!fragment || fragment.length < 2) {
    return { error: 'No fragment found in URL' };
  }
  
  const params = parseFragment(fragment);
  
  if (params.error) {
    console.error('OAuth error:', params.error);
    return { 
      error: params.error, 
      errorDescription: params.error_description || 'Authentication failed' 
    };
  }
  
  const storedState = secureStorage.getItem('oauth_state');
  const storedNonce = secureStorage.getItem('oauth_nonce');
  const storedTimestamp = secureStorage.getItem('oauth_timestamp');
  
  if (!storedState || !storedNonce || !storedTimestamp) {
    return { error: 'Invalid session state' };
  }
  
  if (!validateState(params.state)) {
    return { error: 'Invalid state format' };
  }
  
  if (params.state !== storedState) {
    return { error: 'State mismatch - possible CSRF attack' };
  }
  
  const timestamp = parseInt(storedTimestamp, 10);
  if (Date.now() - timestamp > 600000) {
    return { error: 'Authentication timeout' };
  }
  
  if (!validateToken(params.access_token)) {
    return { error: 'Invalid token format' };
  }
  
  if (params.token_type && params.token_type.toLowerCase() !== 'bearer') {
    return { error: 'Unsupported token type' };
  }
  
  const expiresIn = parseInt(params.expires_in, 10) || 3600;
  
  secureStorage.setItem('access_token', params.access_token, expiresIn);
  secureStorage.setItem('token_expiry', (Date.now() + expiresIn * 1000).toString(), expiresIn);
  
  secureStorage.removeItem('oauth_state');
  secureStorage.removeItem('oauth_nonce');
  secureStorage.removeItem('oauth_timestamp');
  
  window.history.replaceState({}, document.title, window.location.pathname);
  
  return { 
    success: true, 
    accessToken: params.access_token,
    expiresIn: expiresIn 
  };
};

const getAccessToken = () => {
  const token = secureStorage.getItem('access_token');
  const expiry = secureStorage.getItem('token_expiry');
  
  if (!token || !expiry) return null;
  
  if (Date.now() >= parseInt(expiry, 10)) {
    logout();
    return null;
  }
  
  return token;
};

const logout = () => {
  secureStorage.removeItem('access_token');
  secureStorage.removeItem('token_expiry');
  secureStorage.removeItem('oauth_state');
  secureStorage.removeItem('oauth_nonce');
  secureStorage.removeItem('oauth_timestamp');
};

const makeAuthenticatedRequest = async (url, options = {}) => {
  const token = getAccessToken();
  
  if (!token) {
    throw new Error('No valid access token');
  }
  
  const headers = {
    ...options.headers,
    'Authorization': `Bearer ${token}`
  };
  
  const response = await fetch(url, {
    ...options,
    headers
  });
  
  if (response.status === 401) {
    logout();
    throw new Error('Token expired or invalid');
  }
  
  return response;
};

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [user, setUser] = useState(null);
  const [error, setError] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const checkAuth = () => {
      const token = getAccessToken();
      if (token) {
        setIsAuthenticated(true);
        setLoading(false);
      } else {
        setIsAuthenticated(false);
        setLoading(false);
      }
    };

    checkAuth();
  }, []);

  const handleLogin = async () => {
    try {
      await initiateOAuthFlow();
    } catch (err) {
      setError('Failed to initiate login');
      console.error(err);
    }
  };

  const handleLogout = () => {
    logout();
    setIsAuthenticated(false);
    setUser(null);
    setError(null);
  };

  const fetchUserData = async () => {
    try {
      const response = await makeAuthenticatedRequest('https://your-api.com/user');
      const userData = await response.json();
      setUser(userData);
    } catch (err) {
      setError('Failed to fetch user data');
      console.error(err);
    }
  };

  if (loading) {
    return <div style={styles.container}>Loading...</div>;
  }

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>OAuth 2.0 Implicit Flow Demo</h1>
      
      {error && (
        <div style={styles.error}>
          {error}
        </div>
      )}
      
      {!isAuthenticated ? (
        <div style={styles.loginSection}>
          <p>Please log in to continue</p>
          <button onClick={handleLogin} style={styles.button}>
            Login with OAuth
          </button>
        </div>
      ) : (
        <div style={styles.authenticatedSection}>
          <p style={styles.success}>Successfully authenticated!</p>
          <button onClick={fetchUserData} style={styles.button}>
            Fetch User Data
          </button>
          <button onClick={handleLogout} style={styles.buttonSecondary}>
            Logout
          </button>
          
          {user && (
            <div style={styles.userData}>
              <h3>User Data:</h3>
              <pre>{JSON.stringify(user, null, 2)}</pre>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

const CallbackPage = () => {
  const [status, setStatus] = useState('Processing...');

  useEffect(() => {
    const result = handleCallback();
    
    if (result.error) {
      setStatus(`Error: ${result.error}`);
      setTimeout(() => {
        window.location.href = '/';
      }, 3000);
    } else if (result.success) {
      setStatus('Authentication successful! Redirecting...');
      setTimeout(() => {
        window.location.href = '/';
      }, 1000);
    }
  }, []);

  return (
    <div style={styles.container}>
      <h2>{status}</h2>
    </div>
  );
};

